const body = $input.first().json.body || $input.first().json;
const text = body.text || '';
const userLat = parseFloat(body.lat) || 37.5665;
const userLng = parseFloat(body.lng) || 126.9780;
const userTransportMode = body.transportMode || 'transit';
const locationName = body.locationName || '';

// '근처' 쿼리에 실제 동네명 붙이기 (예: '근처 맛집' → '역삼동 맛집')
let enrichedText = text;
if (locationName && /근처/.test(text)) {
  enrichedText = text.replace('근처', locationName);
}

return [{
  json: {
    text: enrichedText,
    originalText: text,
    userLat,
    userLng,
    userTransportMode,
    locationName,
  }
}];

